/**
 * @gao/http — Error Handler Middleware
 *
 * Global error handler that wraps the entire pipeline in try-catch.
 * Converts all errors into proper HTTP responses.
 *
 * Should be the OUTERMOST middleware in the pipeline.
 */

import type { MiddlewareHandler } from '../middleware.js';
import type { GaoRequest } from '../request.js';
import type { GaoResponse } from '../response.js';
import { errorHandler } from '../error-handler.js';

export interface ErrorHandlerOptions {
    /** Show detailed error info (stack traces, messages). Defaults to NODE_ENV !== 'production'. */
    debug?: boolean;
    /** Custom error renderer — return an HTML Response for errors instead of JSON */
    onError?: (error: unknown, statusCode: number, req: GaoRequest, res: GaoResponse, debug: boolean) => Response | Promise<Response>;
}

/**
 * Error handler middleware — catches all downstream errors.
 */
export function errorHandlerMiddleware(options: ErrorHandlerOptions = {}): MiddlewareHandler {
    const debug = options.debug ?? process.env.NODE_ENV !== 'production';

    return async (req, res, next) => {
        try {
            return await next();
        } catch (error) {
            if (options.onError) {
                const statusCode = getStatusCode(error);
                try {
                    return await options.onError(error, statusCode, req, res, debug);
                } catch {
                    // Fallback to default if custom handler itself fails
                }
            }
            return errorHandler(error);
        }
    };
}

function getStatusCode(error: unknown): number {
    if (error && typeof error === 'object') {
        if ('statusCode' in error && typeof (error as any).statusCode === 'number') return (error as any).statusCode;
        if ('status' in error && typeof (error as any).status === 'number') return (error as any).status;
    }
    return 500;
}
